challenge.solution:
public class Main {
    public static void main(String[] args) {
        int temperature = 30;
        if (temperature >= 30) {
            System.out.println("It's hot! Wear shorts. ☀️");
        } else if (temperature >= 15) {
            System.out.println("Nice weather. Wear a t-shirt. 🙂");
        } else {
            System.out.println("It's cold! Wear a jacket. 🧥");
        }
    }
}
